param($ModuleName = 'dbatools')

Describe "Copy-DbaDbAssembly Unit Tests" -Tag 'UnitTests' {
    Context "Validate parameters" {
        BeforeAll {
            $CommandName = $PSCommandPath.Split('\')[-1].Replace(".Tests.ps1", "")
            $Command = Get-Command -Name $CommandName
        }
        It "Should have Source parameter" {
            $Command | Should -HaveParameter Source
        }
        It "Should have SourceSqlCredential parameter" {
            $Command | Should -HaveParameter SourceSqlCredential
        }
        It "Should have Destination parameter" {
            $Command | Should -HaveParameter Destination
        }
        It "Should have DestinationSqlCredential parameter" {
            $Command | Should -HaveParameter DestinationSqlCredential
        }
        It "Should have Assembly parameter" {
            $Command | Should -HaveParameter Assembly
        }
        It "Should have ExcludeAssembly parameter" {
            $Command | Should -HaveParameter ExcludeAssembly
        }
        It "Should have Force parameter" {
            $Command | Should -HaveParameter Force
        }
        It "Should have EnableException parameter" {
            $Command | Should -HaveParameter EnableException
        }
    }
}

